        NodeList nameIdNodes = subject.getElementsByTagNameNS(
                "urn:oasis:names:tc:SAML:2.0:assertion", "NameID");

        if (nameIdNodes.getLength() == 0) {
            throw new SamlProcessingException("Subject must contain a NameID element");
        }

        String nameId = nameIdNodes.item(0).getTextContent().trim();
        if (nameId.isEmpty()) {
            throw new SamlProcessingException("NameID must not be empty");
        }

        return nameId;
