    private void validateSubjectConfirmation(Element subject) throws SamlProcessingException {
        NodeList confirmations = subject.getElementsByTagNameNS(
                "urn:oasis:names:tc:SAML:2.0:assertion", "SubjectConfirmation");

        for (int i = 0; i < confirmations.getLength(); i++) {
            Element confirmation = (Element) confirmations.item(i);
            String method = confirmation.getAttribute("Method");

            if ("urn:oasis:names:tc:SAML:2.0:cm:bearer".equals(method)) {
                NodeList confirmationData = confirmation.getElementsByTagNameNS(
                        "urn:oasis:names:tc:SAML:2.0:assertion", "SubjectConfirmationData");

                if (confirmationData.getLength() > 0) {
                    Element data = (Element) confirmationData.item(0);

                    String notOnOrAfter = data.getAttribute("NotOnOrAfter");
                    if (notOnOrAfter != null && !notOnOrAfter.isEmpty()) {
                        Instant expiry = Instant.parse(notOnOrAfter);
                        if (Instant.now().minus(maxClockSkew).isAfter(expiry)) {
                            throw new SamlProcessingException(
                                    "SubjectConfirmationData has expired: " + notOnOrAfter);
                        }
                    }

                    String recipient = data.getAttribute("Recipient");
                    if (recipient != null && !recipient.isEmpty()
                            && !expectedDestination.equals(recipient)) {
                        throw new SamlProcessingException(
                                "SubjectConfirmationData Recipient mismatch. Expected: "
                                        + expectedDestination + ", got: " + recipient);
                    }
                }
                return;
            }
        }

        throw new SamlProcessingException("No valid bearer SubjectConfirmation found");
    }

    private String extractSessionIndex(Element assertionElement) {
        NodeList authnStatements = assertionElement.getElementsByTagNameNS(
                "urn:oasis:names:tc:SAML:2.0:assertion", "AuthnStatement");

        if (authnStatements.getLength() > 0) {
            Element authnStatement = (Element) authnStatements.item(0);
            String sessionIndex = authnStatement.getAttribute("SessionIndex");
            return (sessionIndex != null && !sessionIndex.isEmpty()) ? sessionIndex : null;
        }
        return null;
    }

    private Map<String, List<String>> extractAttributes(Element assertionElement) {
        Map<String, List<String>> attributes = new LinkedHashMap<>();

        NodeList attrStatements = assertionElement.getElementsByTagNameNS(
                "urn:oasis:names:tc:SAML:2.0:assertion", "AttributeStatement");

        for (int i = 0; i < attrStatements.getLength(); i++) {
            Element attrStatement = (Element) attrStatements.item(i);
            NodeList attrNodes = attrStatement.getElementsByTagNameNS(
                    "urn:oasis:names:tc:SAML:2.0:assertion", "Attribute");

            for (int j = 0; j < attrNodes.getLength(); j++) {
                Element attrElement = (Element) attrNodes.item(j);
                String name = attrElement.getAttribute("Name");

                if (name == null || name.isEmpty()) {
                    continue;
                }

                List<String> values = new ArrayList<>();
                NodeList valueNodes = attrElement.getElementsByTagNameNS(
                        "urn:oasis:names:tc:SAML:2.0:assertion", "AttributeValue");

                for (int k = 0; k < valueNodes.getLength(); k++) {
                    String value = valueNodes.item(k).getTextContent();
                    if (value != null) {
                        values.add(value.trim());
                    }
                }

                attributes.put(name, values);
            }
        }

        return attributes;
    }

    private String extractTextContent(Element parent, String namespaceURI, String localName)
            throws SamlProcessingException {
        NodeList nodes = parent.getElementsByTagNameNS(namespaceURI, localName);
        if (nodes.getLength() == 0) {
            throw new SamlProcessingException("Required element not found: " + localName);
        }
        return nodes.item(0).getTextContent().trim();
    }

    private void validateTimestamp(String timestamp, String context) throws SamlProcessingException {
        try {
            Instant instant = Instant.parse(timestamp);
            Instant now = Instant.now();

            if (now.minus(maxClockSkew).isAfter(instant.plus(Duration.ofMinutes(30)))) {
                throw new SamlProcessingException(context + " is too old: " + timestamp);
            }

            if (instant.minus(maxClockSkew).isAfter(now)) {
                throw new SamlProcessingException(context + " is in the future: " + timestamp);
            }
        } catch (SamlProcessingException e) {
            throw e;
        } catch (Exception e) {
            throw new SamlProcessingException("Invalid timestamp format for " + context + ": " + timestamp, e);
        }
    }

    private void checkReplayAttack(String assertionId) throws SamlProcessingException {
        if (!processedAssertionIds.add(assertionId)) {
            throw new SamlProcessingException(
                    "Replay attack detected. Assertion ID already processed: " + assertionId);
        }
    }

