    /**
     * KeySelector that only trusts the configured IdP certificate.
     */
    private static class TrustedKeySelector extends KeySelector {
        private final X509Certificate trustedCertificate;

        TrustedKeySelector(X509Certificate trustedCertificate) {
            this.trustedCertificate = trustedCertificate;
        }

        @Override
        public KeySelectorResult select(KeyInfo keyInfo, Purpose purpose,
                                         AlgorithmMethod method, XMLCryptoContext context)
                throws KeySelectorException {

            PublicKey trustedKey = trustedCertificate.getPublicKey();

            if (keyInfo != null) {
                @SuppressWarnings("unchecked")
                List<XMLStructure> content = keyInfo.getContent();
                for (XMLStructure structure : content) {
                    if (structure instanceof X509Data) {
                        @SuppressWarnings("unchecked")
                        List<?> x509Content = ((X509Data) structure).getContent();
                        for (Object item : x509Content) {
                            if (item instanceof X509Certificate) {
                                X509Certificate cert = (X509Certificate) item;
                                if (!cert.equals(trustedCertificate)) {
                                    throw new KeySelectorException(
                                            "Untrusted certificate in SAML response");
                                }
                            }
                        }
                    }
                }
            }

            return () -> trustedKey;
        }
    }

    private static class StrictErrorHandler implements org.xml.sax.ErrorHandler {
        @Override
        public void warning(org.xml.sax.SAXParseException e) throws org.xml.sax.SAXException {
            // Log warning but continue
        }

        @Override
        public void error(org.xml.sax.SAXParseException e) throws org.xml.sax.SAXException {
            throw e;
        }

        @Override
        public void fatalError(org.xml.sax.SAXParseException e) throws org.xml.sax.SAXException {
            throw e;
        }
    }

    public static class SamlAssertion {
        private String assertionId;
        private String issuer;
        private String nameId;
        private String sessionIndex;
        private Map<String, List<String>> attributes;

        public String getAssertionId() { return assertionId; }
        public void setAssertionId(String assertionId) { this.assertionId = assertionId; }
        public String getIssuer() { return issuer; }
        public void setIssuer(String issuer) { this.issuer = issuer; }
        public String getNameId() { return nameId; }
        public void setNameId(String nameId) { this.nameId = nameId; }
        public String getSessionIndex() { return sessionIndex; }
        public void setSessionIndex(String sessionIndex) { this.sessionIndex = sessionIndex; }
        public Map<String, List<String>> getAttributes() { return attributes; }
        public void setAttributes(Map<String, List<String>> attributes) { this.attributes = attributes; }

        public String getFirstAttributeValue(String name) {
            List<String> values = attributes != null ? attributes.get(name) : null;
            return (values != null && !values.isEmpty()) ? values.get(0) : null;
        }

        @Override
        public String toString() {
            return "SamlAssertion{" +
                    "assertionId='" + assertionId + '\'' +
                    ", issuer='" + issuer + '\'' +
                    ", nameId='" + nameId + '\'' +
                    ", sessionIndex='" + sessionIndex + '\'' +
                    ", attributes=" + attributes +
                    '}';
        }
    }

    public static class AuthenticatedSession {
        private final String sessionId;
        private final String userId;
        private final String issuer;
        private final Map<String, List<String>> attributes;
        private final Instant createdAt;
        private final Instant expiresAt;
        private final String samlSessionIndex;

        public AuthenticatedSession(String sessionId, String userId, String issuer,
                                     Map<String, List<String>> attributes,
                                     String samlSessionIndex, Duration sessionDuration) {
            this.sessionId = sessionId;
            this.userId = userId;
            this.issuer = issuer;
            this.attributes = Collections.unmodifiableMap(new LinkedHashMap<>(attributes));
            this.createdAt = Instant.now();
            this.expiresAt = createdAt.plus(sessionDuration);
            this.samlSessionIndex = samlSessionIndex;
        }

        public String getSessionId() { return sessionId; }
        public String getUserId() { return userId; }
        public String getIssuer() { return issuer; }
        public Map<String, List<String>> getAttributes() { return attributes; }
        public Instant getCreatedAt() { return createdAt; }
        public Instant getExpiresAt() { return expiresAt; }
        public String getSamlSessionIndex() { return samlSessionIndex; }

        public boolean isExpired() {
            return Instant.now().isAfter(expiresAt);
        }

        public String getAttributeValue(String name) {
            List<String> values = attributes.get(name);
            return (values != null && !values.isEmpty()) ? values.get(0) : null;
        }

        @Override
        public String toString() {
            return "AuthenticatedSession{" +
                    "sessionId='" + sessionId + '\'' +
                    ", userId='" + userId + '\'' +
                    ", issuer='" + issuer + '\'' +
                    ", createdAt=" + createdAt +
                    ", expiresAt=" + expiresAt +
                    '}';
        }
    }

    public static class SessionManager {
        private final ConcurrentHashMap<String, AuthenticatedSession> activeSessions;
        private final Duration defaultSessionDuration;

        public SessionManager() {
            this(Duration.ofHours(8));
        }

        public SessionManager(Duration defaultSessionDuration) {
            this.activeSessions = new ConcurrentHashMap<>();
            this.defaultSessionDuration = defaultSessionDuration;
        }

        public AuthenticatedSession createSession(SamlAssertion assertion) {
            String sessionId = generateSecureSessionId();

            AuthenticatedSession session = new AuthenticatedSession(
                    sessionId,
                    assertion.getNameId(),
                    assertion.getIssuer(),
                    assertion.getAttributes() != null ? assertion.getAttributes() : Collections.emptyMap(),
                    assertion.getSessionIndex(),
                    defaultSessionDuration
            );

            activeSessions.put(sessionId, session);
            return session;
        }

        public AuthenticatedSession getSession(String sessionId) {
            AuthenticatedSession session = activeSessions.get(sessionId);
            if (session != null && session.isExpired()) {
                activeSessions.remove(sessionId);
                return null;
            }
            return session;
        }

        public void invalidateSession(String sessionId) {
            activeSessions.remove(sessionId);
        }

        public void invalidateBySamlSessionIndex(String samlSessionIndex) {
            if (samlSessionIndex == null) return;
            activeSessions.entrySet().removeIf(entry ->
                    samlSessionIndex.equals(entry.getValue().getSamlSessionIndex()));
        }

        public void cleanupExpiredSessions() {
            activeSessions.entrySet().removeIf(entry -> entry.getValue().isExpired());
        }

        private String generateSecureSessionId() {
            SecureRandom random = new SecureRandom();
            byte[] bytes = new byte[32];
            random.nextBytes(bytes);
            StringBuilder sb = new StringBuilder();
            for (byte b : bytes) {
                sb.append(String.format("%02x", b));
            }
            return sb.toString();
        }
    }

    public static class SamlProcessingException extends Exception {
        public SamlProcessingException(String message) {
            super(message);
        }

        public SamlProcessingException(String message, Throwable cause) {
            super(message, cause);
        }
    }

